import { Avatar as AvatarPrimitive, useAvatar, useAvatarContext } from '@ark-ui/react/avatar';
import { clsx } from 'clsx';
import { forwardRef, type ComponentProps, type ComponentRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Avatar.module.css';

type AvatarSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
type AvatarRootProps = ComponentProps<typeof AvatarPrimitive.Root> & {
  size?: AvatarSize;
};
type AvatarRootProviderProps = ComponentProps<typeof AvatarPrimitive.RootProvider> & {
  size?: AvatarSize;
};
type AvatarFallbackProps = ComponentProps<typeof AvatarPrimitive.Fallback> & {
  name?: string;
};

const getInitials = (name: string) => {
  const parts = name.trim().split(/\s+/).filter(Boolean);
  const firstName = parts[0] ?? '';
  const lastName = parts.length > 1 ? parts[parts.length - 1] : '';

  return firstName && lastName ? `${firstName[0]}${lastName[0]}` : (firstName[0] ?? '');
};

const AvatarRoot = forwardRef<ComponentRef<typeof AvatarPrimitive.Root>, AvatarRootProps>(
  function AvatarRoot({ className, size, ...props }, ref) {
    return (
      <AvatarPrimitive.Root
        ref={ref}
        data-slot="avatar-root"
        data-size={size}
        className={clsx(styles.root, normalizeClassName(className))}
        {...props}
      />
    );
  },
);

const AvatarRootProvider = forwardRef<
  ComponentRef<typeof AvatarPrimitive.RootProvider>,
  AvatarRootProviderProps
>(function AvatarRootProvider({ className, size, ...props }, ref) {
  return (
    <AvatarPrimitive.RootProvider
      ref={ref}
      data-slot="avatar-root-provider"
      data-size={size}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const AvatarImage = forwardRef<
  ComponentRef<typeof AvatarPrimitive.Image>,
  ComponentProps<typeof AvatarPrimitive.Image>
>(function AvatarImage({ className, ...props }, ref) {
  return (
    <AvatarPrimitive.Image
      ref={ref}
      data-slot="avatar-image"
      className={clsx(styles.image, normalizeClassName(className))}
      {...props}
    />
  );
});

const AvatarFallback = forwardRef<
  ComponentRef<typeof AvatarPrimitive.Fallback>,
  AvatarFallbackProps
>(function AvatarFallback({ children, className, name, ...props }, ref) {
  return (
    <AvatarPrimitive.Fallback
      ref={ref}
      data-slot="avatar-fallback"
      className={clsx(styles.fallback, normalizeClassName(className))}
      {...props}
    >
      {children ?? (name ? getInitials(name) : undefined)}
    </AvatarPrimitive.Fallback>
  );
});

const Avatar = Object.assign(AvatarRoot, {
  Root: AvatarRoot,
  RootProvider: AvatarRootProvider,
  Image: AvatarImage,
  Fallback: AvatarFallback,
});

export { Avatar, useAvatar, useAvatarContext };

@layer moduix.components {
  .root {
    box-sizing: border-box;
    display: inline-flex;
    width: var(--moduix-avatar-size, var(--moduix-size-md));
    height: var(--moduix-avatar-size, var(--moduix-size-md));
    flex-shrink: 0;
    align-items: center;
    justify-content: center;
    overflow: hidden;
    position: relative;
    border-radius: var(--moduix-avatar-radius, var(--moduix-radius-full));
    background-color: var(--moduix-avatar-bg, var(--moduix-color-muted));
    color: var(--moduix-avatar-color, var(--moduix-color-foreground));
    font-size: var(--moduix-avatar-font-size, var(--moduix-text-md));
    font-weight: var(--moduix-avatar-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-avatar-line-height, var(--moduix-line-height-text-md));
    user-select: none;
    vertical-align: middle;

    &:where([data-size='xs']) {
      --moduix-avatar-size: var(--moduix-size-xs);
      --moduix-avatar-font-size: var(--moduix-text-xs);
      --moduix-avatar-line-height: var(--moduix-line-height-text-xs);
    }

    &:where([data-size='sm']) {
      --moduix-avatar-size: var(--moduix-size-sm);
      --moduix-avatar-font-size: var(--moduix-text-sm);
      --moduix-avatar-line-height: var(--moduix-line-height-text-sm);
    }

    &:where([data-size='lg']) {
      --moduix-avatar-size: var(--moduix-size-lg);
      --moduix-avatar-font-size: var(--moduix-text-lg);
      --moduix-avatar-line-height: var(--moduix-line-height-text-lg);
    }

    &:where([data-size='xl']) {
      --moduix-avatar-size: var(--moduix-size-xl);
      --moduix-avatar-font-size: var(--moduix-text-lg);
      --moduix-avatar-line-height: var(--moduix-line-height-text-lg);
    }
  }

  .image {
    display: block;
    width: 100%;
    height: 100%;
    object-fit: var(--moduix-avatar-image-object-fit, cover);
    object-position: var(--moduix-avatar-image-object-position, center);
    border-radius: inherit;

    &[data-state='hidden'] {
      display: none;
    }
  }

  .fallback {
    display: inline-flex;
    width: 100%;
    height: 100%;
    align-items: center;
    justify-content: center;
    padding: var(--moduix-avatar-fallback-padding, 0);
    background-color: var(
      --moduix-avatar-fallback-bg,
      var(--moduix-avatar-bg, var(--moduix-color-muted))
    );
    color: var(--moduix-avatar-fallback-color, inherit);
    border-radius: inherit;
    line-height: 1;

    &[data-state='hidden'] {
      display: none;
    }
  }
}
